import React from "react";
import './FeaturedMovie.css';

export default ({ item }) => {

  if (!item) return null;

  const firstDate = item.first_air_date
    ? new Date(item.first_air_date)
    : item.release_date
      ? new Date(item.release_date)
      : null;

  const genres = item.genres
    ? item.genres.map(g => g.name)
    : [];

  let description = item.overview || item.description || "";

  if (description.length > 200) {
    description = description.substring(0, 200) + "...";
  }

  const background =
    item.backdrop_path || item.backdrop || "";

  return (
    <section
      className="featured"
      style={{
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundImage: background
          ? `url(https://image.tmdb.org/t/p/original${background})`
          : 'none'
      }}
    >

      <div className="featured--vertical">
        <div className="featured--horizontal">

          <div className="featured--name">
            {item.original_name || item.title || item.name}
          </div>

          <div className="featured--info">
            <div className="featured--points">
              {item.vote_average || item.rating || 0} pontos
            </div>

            <div className="featured--year">
              {firstDate ? firstDate.getFullYear() : "—"}
            </div>

            <div className="featured--seasons">
              {item.number_of_seasons
                ? `${item.number_of_seasons} temporada(s)`
                : ""}
            </div>
          </div>

          <div className="featured--description">
            {description}
          </div>

          <div className="featured--buttons">
            <a href={`/watch/${item.id}`} className="featured--watchbutton">
              ► Assistir
            </a>
            <a href={`/list/add/${item.id}`} className="featured--mylistbutton">
              + Minha Lista
            </a>
          </div>

          <div className="featured--genres">
            <strong>Gêneros:</strong> {genres.join(', ')}
          </div>

        </div>
      </div>

    </section>
  );
};
